Here are the key modern MSTest patterns for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Mock handler lets you control HttpClient responses without real HTTP
    private static HttpClient CreateMockClient(HttpStatusCode status, string content = "")
    {
        var handler = new MockHttpMessageHandler(status, content);
        return new HttpClient(handler);
    }

    // 1. Basic async test — return Task, not void
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2. [Timeout] — enforces a wall-clock limit on async tests.
    //    MSTest cancels the test's CancellationToken when time expires.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "fast");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com",
            TestContext.CancellationTokenSource.Token);  // linked to [Timeout]

        Assert.AreEqual("fast", result);
    }

    // 3. Cancellation — verify the method respects a cancelled token
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // 4. Error status codes
    [TestMethod]
    public async Task FetchAsync_ThrowsOnServerError()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    public TestContext TestContext { get; set; } = null!;
}

// Reusable fake handler — no mocking library needed
internal sealed class MockHttpMessageHandler(
    HttpStatusCode statusCode, string content = "") : HttpMessageHandler
{
    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        var response = new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content)
        };
        return Task.FromResult(response);
    }
}
```

**Key patterns summarized:**

| Pattern | How |
|---|---|
| Async tests | Return `Task`, never `async void` |
| Timeouts | `[Timeout(ms)]` — auto-cancels via `TestContext.CancellationTokenSource.Token` |
| Cancellation | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| Async assertions | `Assert.ThrowsExactlyAsync<T>()` (MSTest v3.8+) |
| Mock HttpClient | Custom `HttpMessageHandler` — no library needed |

`TestContext.CancellationTokenSource.Token` is the critical link: it connects `[Timeout]` to your code's `CancellationToken`, so timeouts actually cancel in-flight work rather than just failing the test after it finishes.
